Subject: ACPI : Discard EC burst mode when burst mode timeout happens

---
 drivers/acpi/ec.c |   41 ++++++++++++++++++++++++++++++++++++++++-
 1 file changed, 40 insertions(+), 1 deletion(-)

Index: linux-2.6/drivers/acpi/ec.c
===================================================================
--- linux-2.6.orig/drivers/acpi/ec.c
+++ linux-2.6/drivers/acpi/ec.c
@@ -110,6 +110,8 @@ static struct acpi_ec {
 	u8 handlers_installed;
 } *boot_ec, *first_ec;

+static unsigned int ec_burst_timeout;
+
 /* --------------------------------------------------------------------------
                              Transaction Management
    -------------------------------------------------------------------------- */
@@ -300,11 +302,48 @@ static int acpi_ec_transaction(struct ac
 int acpi_ec_burst_enable(struct acpi_ec *ec)
 {
 	u8 d;
-	return acpi_ec_transaction(ec, ACPI_EC_BURST_ENABLE, NULL, 0, &d, 1, 0);
+	int status = 0;
+
+	/*
+	 * If the burst mode is disabled, it will return directly.
+	 */
+	if (ec_burst_timeout)
+		return 0;
+
+	status = acpi_ec_transaction(ec, ACPI_EC_BURST_ENABLE, NULL, 0,
+					&d, 1, 0);
+	if (status == -ETIME) {
+		/*
+		 * When timeouts happends, the burst mode will be disabled.
+		 * In such case OS won't use burst mode again in the following
+		 * transaction sequence.
+		 */
+		ec_burst_timeout = 1;
+	}
+	return status;
 }

 int acpi_ec_burst_disable(struct acpi_ec *ec)
 {
+	u8 ec_status;
+
+	if (ec_burst_timeout) {
+		/*
+		 * If burst mode is disabled, it means that the EC won't
+		 * enter the burst mode again. In such case it is unnecessary
+		 * to issue the BURST_DISABLE command.
+		 */
+		return 0;
+	}
+
+	ec_status = acpi_ec_read_status(ec);
+	if (!(ec_status & ACPI_EC_FLAG_BURST)) {
+		/*
+		 * If the EC has exit the burst mode already,it is unnecessary
+		 * to issue the BURST_DISABLE command again.
+		 */
+		return 0;
+	}
 	return acpi_ec_transaction(ec, ACPI_EC_BURST_DISABLE, NULL, 0, NULL, 0, 0);
 }
